      plane: XY_PLANE,
      outer: {
        segs: [
          { id: 'tri.s0', a: p0, b: p1 },
          { id: 'tri.s1', a: p1, b: p2 },
          { id: 'tri.s2', a: p2, b: p0 },
        ],
      },
    };
    const s = unwrap(extrude(tri, { dist: 1 }));
    expect(s.vertices.size).toBe(6);
    expect(s.edges.size).toBe(9);
    expect(s.faces.size).toBe(5);
    expect(s.halfEdges.size).toBe(18);
    expect(validateSolid(s)).toEqual([]);
  });
});
